#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline int read(){
    int x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(int x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
CI MAXN=1e6+5;
int l,r,tot=0,prime[MAXN];
bool vis[MAXN],num[MAXN];
void init()
{
    memset(vis,false,sizeof(vis));
    vis[1]=vis[0]=true;
    for(int i=2;i<MAXN;++i)
    {
        if(!vis[i]) prime[tot++]=i;
        for(int j=0;j<tot;++j)
        {
            if(i*prime[j]>=MAXN) break;
            vis[prime[j]*i]=true;
            if(i%prime[j]==0) break;
        }
    }
}
int main(void)
{
    init();
    memset(num,false,sizeof(num));
    l=read(),r=read();
    for(int i=0;i<tot&&prime[i]*prime[i]<=r;++i)
    {
        for(ll j=(l/prime[i])*prime[i];j<=r;j+=prime[i])
        {
            if(j>=l&&j!=prime[i])
            {
                num[j-l]=true;
            }
        }
    }
    int ans=0;
    for(int i=0;i<=r-l;++i)
        if(!num[i])++ans;
    write(ans);
    return false;
}
